import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

// This demo also loads: https://apexcharts.com/samples/assets/stock-prices.js

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [
      {
        data: [344, 345, 333, 323, 322, 342, 383, 353, 323, 376],
      },
    ],
    options: {
      chart: {
        height: 350,
        type: 'area',
        zoom: {
          enabled: false,
        },
        events: {
          mounted: function (ctx, config) {
            var lowest = ctx.getLowestValueInSeries(0)
            var highest = ctx.getHighestValueInSeries(0)

            ctx.addPointAnnotation({
              x: new Date(
                ctx.w.globals.seriesX[0][
                  ctx.w.globals.series[0].indexOf(lowest)
                ],
              ).getTime(),
              y: lowest,
              label: {
                text: 'Lowest: ' + lowest,
                offsetY: 2,
              },
              image: {
                path: '../../assets/images/ico-instagram.png',
                width: undefined,
                height: undefined,
                offsetX: 0,
                offsetY: -18,
              },
            })

            ctx.addPointAnnotation({
              x: new Date(
                ctx.w.globals.seriesX[0][
                  ctx.w.globals.series[0].indexOf(highest)
                ],
              ).getTime(),
              y: highest,
              label: {
                text: 'Highest: ' + highest,
                offsetY: 2,
              },
            })
          },
        },
      },
      dataLabels: {
        enabled: false,
      },
      stroke: {
        curve: 'straight',
      },
    },
  })

  return (
    <div>
      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="area"
          height={350}
        />
      </div>
    </div>
  )
}

export default ApexChart
